    day: 27, phase: 1, week: 4,
    title: "Prepositions of Place",
    grammar: "<b>Prepositions of Place</b><br><br><table class='conj-table'><tr><th>Spanish</th><th>English</th></tr><tr><td><b>en</b></td><td>in/on</td></tr><tr><td><b>sobre / encima de</b></td><td>on/over/on top of</td></tr><tr><td><b>debajo de</b></td><td>under</td></tr><tr><td><b>detrás de</b></td><td>behind</td></tr><tr><td><b>delante de</b></td><td>in front of</td></tr><tr><td><b>al lado de</b></td><td>next to</td></tr><tr><td><b>entre</b></td><td>between</td></tr><tr><td><b>cerca de</b></td><td>near</td></tr><tr><td><b>lejos de</b></td><td>far from</td></tr><tr><td><b>dentro de</b></td><td>inside</td></tr></table><br><b>Examples:</b><br>El libro está <b>en</b> la mesa.<br>El gato está <b>debajo de</b> la cama.<br>La biblioteca está <b>al lado de</b>l parque.<br>El banco está <b>entre</b> el café y la tienda.<br>Mi casa está <b>cerca de</b> la escuela.",
    vocab: { theme: "Prepositions of Place", words: [{es:"en",en:"in/on"},{es:"sobre",en:"on/over"},{es:"debajo de",en:"under"},{es:"detrás de",en:"behind"},{es:"delante de",en:"in front of"},{es:"al lado de",en:"next to"},{es:"entre",en:"between"},{es:"cerca de",en:"near"},{es:"lejos de",en:"far from"},{es:"dentro de",en:"inside"},{es:"fuera de",en:"outside"},{es:"encima de",en:"on top of"}] },
