    grammar: "<b>Prepositions of Time</b><br><br><table class='conj-table'><tr><th>Spanish</th><th>English</th></tr><tr><td><b>antes (de)</b></td><td>before</td></tr><tr><td><b>después (de)</b></td><td>after</td></tr><tr><td><b>durante</b></td><td>during</td></tr><tr><td><b>hasta</b></td><td>until</td></tr><tr><td><b>desde</b></td><td>since/from</td></tr><tr><td><b>por la mañana</b></td><td>in the morning</td></tr><tr><td><b>por la tarde</b></td><td>in the afternoon</td></tr><tr><td><b>por la noche</b></td><td>at night</td></tr><tr><td><b>a tiempo</b></td><td>on time</td></tr><tr><td><b>temprano</b></td><td>early</td></tr><tr><td><b>tarde</b></td><td>late</td></tr><tr><td><b>a mediodía</b></td><td>at noon</td></tr></table><br><b>Examples:</b><br>Estudio <b>antes de</b> comer.<br>Duermo <b>después de</b> cenar.<br>Trabajo <b>durante</b> el día.<br>La tienda está abierta <b>hasta</b> las ocho.<br>Vivo aquí <b>desde</b> 2010.<br>Estudio <b>por la noche</b>.",
    vocab: { theme: "Time Expressions", words: [{es:"antes",en:"before"},{es:"después",en:"after"},{es:"durante",en:"during"},{es:"hasta",en:"until"},{es:"desde",en:"since/from"},{es:"a tiempo",en:"on time"},{es:"temprano",en:"early"},{es:"tarde",en:"late"},{es:"por la mañana",en:"in the morning"},{es:"por la tarde",en:"in the afternoon"},{es:"por la noche",en:"at night"},{es:"a mediodía",en:"at noon"}] },
