    grammar: "<b>Week 19 Review</b><br><br><b>Para:</b> purpose, recipient, deadline, destination<br><b>Por:</b> cause, duration, exchange, through, means, per<br><br><b>Past progressive:</b> estaba + -ando/-iendo<br>Estaba durmiendo cuando sonó el despertador.<br><br><b>Connectors:</b> Primero, luego, después, además, sin embargo, por eso, así que, finalmente<br><br><b>Narrative combo:</b> Set scene (imp) + ongoing action (prog) + events (pret)<br><br><b>Key practice phrase:</b> Primero, estaba leyendo cuando de repente alguien llamó a la puerta. Me levanté y abrí. Era mi vecino que necesitaba ayuda.",
    vocab: { theme: "Week 19 Review", words: [{es:"narrar",en:"to narrate"},{es:"describir",en:"to describe"},{es:"conectar",en:"to connect"},{es:"expresar",en:"to express"},{es:"combinar",en:"to combine"},{es:"avanzar",en:"to advance"},{es:"mejorar",en:"to improve"},{es:"practicar",en:"to practice"},{es:"repasar",en:"to review"},{es:"dominar",en:"to master"}] },
